e, or rehydrate the workload and leave behind the evidence needed for support and audit.","inputArtifactId":"Operations Execution Packet","outputArtifactId":"Delivery Summary","handoffLabel":"Delivery completion hand-off to capability owner","handoffProtocolId":"HANDOFF-CAPABILITYIDTOKEN-DELIVERY-OPERATE","exitCriteria":["Delivery action completed","Operational verification recorded","Closure evidence published"],"templatePath":"/out/steps/brokerage-delivery-template.md","allowedToolIds":["workspace_read","git_status","run_deploy","run_docs"],"executionNotes":"Delivery execution remains approval-gated and should only run approved deployment or documentation commands.","artifactContract":{"requiredInputs":["Operations Execution Packet","Delivery Conditions Register","Rollback Plan"],"expectedOutputs":["Delivery Summary","Operational Verification Report","Support Follow-up List"],"notes":"Delivery should conclude with a clear operational record of what changed, how it verified, and what support should expect next."}}]}'::TEXT AS workflow_template
),
workflow_payload AS (
  SELECT
    seed.capability_id,
    seed.capability_slug,
    seed.owner_agent_id,
    template.workflow_suffix,
    template.workflow_name,
    template.workflow_summary,
    REPLACE(
      REPLACE(
        template.workflow_template,
        'OWNERAGENTTOKEN',
        seed.owner_agent_id
      ),
      'CAPABILITYIDTOKEN',
      seed.capability_slug
    )::jsonb AS payload
  FROM tmp_singularity_seed_capabilities seed
  CROSS JOIN workflow_templates template
)
INSERT INTO capability_workflows (
  capability_id,
  id,
  name,
  status,
  workflow_type,
  scope,
  summary,
  schema_version,
  entry_node_id,
  nodes,
  edges,
  steps,
  publish_state,
  created_at,
  updated_at
)
SELECT
  capability_id,
  'WF-' || capability_slug || '-' || workflow_suffix,
  workflow_name,
  'STABLE',
  'SDLC',
  'CAPABILITY',
  workflow_summary,
  2,
  'NODE-' || capability_slug || '-START',
  payload->'nodes',
  payload->'edges',
  payload->'steps',
  'PUBLISHED',
  NOW(),
  NOW()
FROM workflow_payload
ON CONFLICT (capability_id, id) DO UPDATE SET
  name = EXCLUDED.name,
  status = EXCLUDED.status,
  workflow_type = EXCLUDED.workflow_type,
  scope = EXCLUDED.scope,
  summary = EXCLUDED.summary,
  schema_version = EXCLUDED.schema_version,
  entry_node_id = EXCLUDED.entry_node_id,
  nodes = EXCLUDED.nodes,
  edges = EXCLUDED.edges,
  steps = EXCLUDED.steps,
  publish_state = EXCLUDED.publish_state,
  updated_at = NOW();

COMMIT;
